import * as fs from 'fs/promises';
import { ApplicationFailure } from '@temporalio/activity';

const ACCOUNTS_FILE = '/workspace/accounts.json';

async function readAccounts(): Promise<Record<string, number>> {
  const data = await fs.readFile(ACCOUNTS_FILE, 'utf8');
  return JSON.parse(data);
}

async function writeAccounts(accounts: Record<string, number>): Promise<void> {
  await fs.writeFile(ACCOUNTS_FILE, JSON.stringify(accounts, null, 2));
}

export async function withdraw(account: string, amount: number): Promise<void> {
  console.log(`Withdrawing ${amount} from ${account}`);
  const accounts = await readAccounts();
  if (!accounts[account] && accounts[account] !== 0) {
    accounts[account] = 0;
  }
  accounts[account] -= amount;
  await writeAccounts(accounts);
}

export async function deposit(account: string, amount: number): Promise<void> {
  console.log(`Depositing ${amount} to ${account}`);
  if (account === 'B_FAIL') {
    throw ApplicationFailure.create({
      message: 'Intentional deposit failure for B_FAIL',
      nonRetryable: true,
    });
  }
  const accounts = await readAccounts();
  if (!accounts[account] && accounts[account] !== 0) {
    accounts[account] = 0;
  }
  accounts[account] += amount;
  await writeAccounts(accounts);
}

export async function refund(account: string, amount: number): Promise<void> {
  console.log(`Refunding ${amount} to ${account}`);
  const accounts = await readAccounts();
  if (!accounts[account] && accounts[account] !== 0) {
    accounts[account] = 0;
  }
  accounts[account] += amount;
  await writeAccounts(accounts);
}

import { proxyActivities } from '@temporalio/workflow';
import type * as activities from './activities';

const { withdraw, deposit, refund } = proxyActivities<typeof activities>({
  startToCloseTimeout: '1 minute',
  retry: {
    maximumAttempts: 2,
  },
});

interface MoneyTransferInput {
  fromAccount: string;
  toAccount: string;
  amount: number;
}

export async function MoneyTransfer(input: MoneyTransferInput): Promise<void> {
  const { fromAccount, toAccount, amount } = input;

  await withdraw(fromAccount, amount);

  try {
    await deposit(toAccount, amount);
  } catch (err) {
    console.log(`Deposit failed, initiating refund to ${fromAccount}`);
    await refund(fromAccount, amount);
    throw err;
  }
}

import { Worker, NativeConnection } from '@temporalio/worker';
import * as activities from './activities';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE || 'default';
  const apiKey = process.env.TEMPORAL_API_KEY;

  if (!address || !apiKey) {
    throw new Error('TEMPORAL_ADDRESS and TEMPORAL_API_KEY environment variables are required');
  }

  const connection = await NativeConnection.connect({
    address,
    metadata: {
      'api-key': apiKey,
    },
    tls: true,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'saga-ts',
    workflowsPath: require.resolve('./workflows'),
    activities,
  });

  console.log('Worker started, polling saga-ts task queue');
  await worker.run();
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

import { Connection, Client } from '@temporalio/client';
import { MoneyTransfer } from './workflows';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE || 'default';
  const apiKey = process.env.TEMPORAL_API_KEY;
  const zealtRunId = process.env.ZEALT_RUN_ID;

  if (!address || !apiKey || !zealtRunId) {
    throw new Error('TEMPORAL_ADDRESS, TEMPORAL_API_KEY, and ZEALT_RUN_ID environment variables are required');
  }

  const connection = await Connection.connect({
    address,
    metadata: {
      'api-key': apiKey,
    },
    tls: true,
  });

  const client = new Client({
    connection,
    namespace,
  });

  console.log('--- Starting Success Path Workflow ---');
  const okWorkflowId = `saga-ok-${zealtRunId}`;
  const handleOk = await client.workflow.start(MoneyTransfer, {
    taskQueue: 'saga-ts',
    workflowId: okWorkflowId,
    args: [{ fromAccount: 'A', toAccount: 'B', amount: 30 }],
  });
  console.log(`Started workflow ${okWorkflowId}`);
  await handleOk.result();
  console.log(`Workflow ${okWorkflowId} completed successfully`);

  console.log('\n--- Starting Failure Path Workflow ---');
  const failWorkflowId = `saga-fail-${zealtRunId}`;
  const handleFail = await client.workflow.start(MoneyTransfer, {
    taskQueue: 'saga-ts',
    workflowId: failWorkflowId,
    args: [{ fromAccount: 'A', toAccount: 'B_FAIL', amount: 50 }],
  });
  console.log(`Started workflow ${failWorkflowId}`);

  try {
    await handleFail.result();
    console.log(`Workflow ${failWorkflowId} unexpectedly completed successfully`);
  } catch (err) {
    console.log(`Workflow ${failWorkflowId} failed as expected: ${err}`);
  }

  console.log('\nSummary:');
  console.log(`- ${okWorkflowId}: COMPLETED`);
  console.log(`- ${failWorkflowId}: FAILED (Compensated)`);
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

import { spawn } from 'child_process';
import * as path from 'path';

async function run() {
  console.log('Starting Worker and Client...');

  const worker = spawn('npx', ['ts-node', 'src/worker.ts'], {
    stdio: 'inherit',
    env: process.env,
  });

  // Give the worker a few seconds to start up
  await new Promise((resolve) => setTimeout(resolve, 5000));

  const client = spawn('npx', ['ts-node', 'src/client.ts'], {
    stdio: 'inherit',
    env: process.env,
  });

  client.on('close', (code) => {
    console.log(`Client exited with code ${code}`);
    worker.kill();
    process.exit(code || 0);
  });

  worker.on('error', (err) => {
    console.error('Worker error:', err);
  });
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});
